try {
const pages = $input.first().json.pages || [];
const markdown = pages.map(p => p.markdown).join('

---PÁGINA---

');

const systemPrompt = `Você é um assistente de análise de extratos bancários. Extraia todas as transações e retorne APENAS um JSON válido.

Formato OBRIGATÓRIO:
{
  "transacao": [
    {
      "data_transacao": "dd/MM/yyyy",
      "tipo": "entrada" ou "saída",
      "descricao": "descrição da transação",
      "categoria": "categoria semântica da transação",
      "entrada": 0,
      "saida": 0
    }
  ]
}

REGRAS:
- A chave do array DEVE ser "transacao"
- Datas SEMPRE no formato dd/MM/yyyy (ex: 05/03/2026)
- "tipo" DEVE ser exatamente "entrada" ou "saída" (com acento)
- "entrada": valor numérico da receita (0 se for saída)
- "saida": valor numérico da despesa (0 se for entrada)
- Valores SEMPRE numéricos sem R$, sem + ou -
- Ignore linhas de SALDO ANTERIOR e SALDO ATUAL
- Se campo não tiver valor, use 0 (não null)
- "categoria": infira a categoria semântica de cada transação pelo contexto da descrição. Valores válidos: Mercado, Restaurante, Delivery, Padaria / Café, Combustível, Uber / Táxi, Estacionamento, Transporte Público, Aluguel, Condomínio, Energia Elétrica, Água / Saneamento, Internet / TV, Telefone / Celular, Gás, Farmácia, Médico / Consulta, Plano de Saúde, Academia / Esporte, Streaming, Assinatura, Lazer / Entretenimento, Roupas / Calçados, Fatura Cartão, Empréstimo / Parcela, Seguro, Investimento, Imposto / Taxa, Salário, Receita, Freelance / Serviço. Use "Outros" apenas quando for impossível inferir.
- Retorne SOMENTE o JSON, sem markdown, sem blocos de código`;

return [{
  json: {
    request_body: {
      model: 'gpt-4o-mini',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: 'Conteúdo do extrato bancário:

' + markdown }
      ],
      max_tokens: 4000
    }
  }
}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Prepara Extração] ' + (e.message || 'Erro desconhecido') } }];
}

try {
const raw = $input.first().json;

let content = '';
try {
  content = raw.choices[0].message.content;
} catch(e) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'Resposta inesperada da API OpenAI: ' + JSON.stringify(raw).substring(0, 300)
  }}];
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch(e) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'JSON inválido retornado pelo LLM: ' + content.substring(0, 300)
  }}];
}

// Tenta múltiplas chaves para máxima robustez
const arr = parsed.transacao ?? parsed.transações ?? parsed.transactions ?? null;

if (!Array.isArray(arr) || arr.length === 0) {
  return [{ json: {
    extracao_ok: false,
    error_code: 'EXTRACAO_ERROR',
    message: 'LLM não retornou array de transações válido. Chaves encontradas: ' + Object.keys(parsed).join(', ')
  }}];
}

return [{ json: {
  extracao_ok: true,
  transacoes: arr,
  total_transacoes: arr.length
}}];
} catch (e) {
  return [{ json: { extracao_ok: false, error_code: 'CODE_ERROR', message: '[FN - Parseia Extração] ' + (e.message || 'Erro desconhecido') } }];
}

