  if (/padaria|confeitaria|cafeteria|boulangerie/.test(t)) return 'Padaria / Caf\u00e9';
  if (/uber|99|cabify|taxi/.test(t)) return 'Uber / T\u00e1xi';
  if (/combustiv|gasolina|etanol|diesel|abastec|posto/.test(t)) return 'Combust\u00edvel';
