  if (/escola|colegio/.test(t)) return 'Mensalidade Escola';
  if (/faculdad|universid|graduac|pos.?grad|ead|curso|capacitac|treinamento|idioma/.test(t)) return 'Curso / Capacita\u00e7\u00e3o';
  if (/livro|apostila|material.?escolar/.test(t)) return 'Livros / Material';
  if (/netflix|spotify|amazon.?prime|disney|hbo|globo.?play|paramount|apple.?tv|deezer/.test(t)) return 'Streaming';
  if (/assinatura|mensalid.?(club|assin|plataform)/.test(t)) return 'Assinatura';
  if (/cinema|teatro|show|ingresso|parque|museu|evento/.test(t)) return 'Lazer / Entretenimento';
  if (/hotel|pousada|hostel|airbnb|hospedagem|passagem|aereo/.test(t)) return 'Viagem / Hotel';
  if (/roupa|calcado|tenis|sandalia|vestuario/.test(t)) return 'Roupas / Cal\u00e7ados';
  if (/eletronico|notebook|computad|tablet/.test(t)) return 'Eletr\u00f4nicos';
  if (/amazon|shopee|magazine|americanas|casas.?bahia|submarino/.test(t)) return 'Compras';
  if (/fatura|cartao|credito/.test(t)) return 'Fatura Cart\u00e3o';
  if (/emprestimo|parcela|financiam/.test(t)) return 'Empr\u00e9stimo / Parcela';
  if (/seguro(?!.?saude)/.test(t)) return 'Seguro';
  if (/investim|aplicac|cdb|tesouro|fundo/.test(t)) return 'Investimento';
  if (/imposto|ipva|irpf|darf/.test(t)) return 'Imposto / Taxa';
  if (/salario|pagamento.?recebido|folha/.test(t)) return 'Sal\u00e1rio';
  if (/freelance|servico.?prest|honorario/.test(t)) return 'Freelance / Servi\u00e7o';
  if (/aluguel.?recebido|renda.?imov/.test(t)) return 'Aluguel Recebido';
  if (/cashback|desconto.?recebido|reembolso/.test(t)) return 'Cashback / Desconto';
  if (/rendimento|dividendo|juros.?recebido/.test(t)) return 'Investimento / Rendimento';
  if (/\\bpet\\b|veterin|racao|animais/.test(t)) return 'Pet';
  return null;
}
// === fim inferirPorTexto ===

function normalizarData(dataStr) {
  if (!dataStr) return null;
  const s = String(dataStr).trim();

  if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) return s;

  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) {
    const [ano, mes, dia] = s.split('-');
    return `${dia}/${mes}/${ano}`;
  }

  if (/^\d{2}-\d{2}-\d{4}$/.test(s)) return s.replace(/-/g, '/');

  const meses = {
    'jan':'01','fev':'02','mar':'03','abr':'04','mai':'05','jun':'06',
    'jul':'07','ago':'08','set':'09','out':'10','nov':'11','dez':'12',
    'janeiro':'01','fevereiro':'02','março':'03','abril':'04','maio':'05',
    'junho':'06','julho':'07','agosto':'08','setembro':'09','outubro':'10',
    'novembro':'11','dezembro':'12'
  };
  const m = s.match(/^(\d{1,2})\s+([a-záàâãéêíóôõúç]+)\.?\s+(\d{4})$/i);
  if (m) {
    const mes = meses[m[2].toLowerCase()];
    if (mes) return `${m[1].padStart(2,'0')}/${mes}/${m[3]}`;
  }

  return null;
}

const dataNormalizada = normalizarData(item.data_transacao);

// Categoria: usa item.categoria se existir, senão 'Outros'
